                columnList = "profile_id"),
        @Index(name = "idx_photo_s3_key",
                columnList = "s3_key", unique = true),
        @Index(name = "idx_photo_primary_profile",
                columnList = "profile_id, is_primary"),
})
public class Photo {
    @Id
